            's14': { text: "Stage 14: You make it onto the rocky shore, freezing.", choices: [{text:"Climb the cliff face.", nextScene:'s15'}, {text:"Walk along the beach.", nextScene:'death_snipe'}] },
            's15': { text: "Stage 15: Halfway up the cliff, she starts shooting at you from the boat.", choices: [{text:"Climb faster.", nextScene:'s16'}, {text:"Hide behind an outcropping.", nextScene:'s16'}] },
