            's17': { text: "Stage 17: In the kitchen, you find a massive chef's knife.", choices: [{text:"Hold it by the door.", nextScene:'s18'}, {text:"Hide under the island.", nextScene:'s18'}] },
            's18': { text: "Stage 18: She walks in, dripping wet. 'Where are you?'", choices: [{text:"Jump out.", nextScene:'s19'}, {text:"Wait.", nextScene:'s19'}] },
