            's20': { text: "Stage 20: She is bleeding heavily but still smiling. 'You can't leave the island anyway. The boat was rigged.'", choices: [{text:"Tape her hands.", nextScene:'s21'}, {text:"Let her bleed.", nextScene:'s21'}] },
            's21': { text: "Stage 21: You hear the bomb on the boat detonate in the distance. The sea cave collapses.", choices: [{text:"Leave her in the kitchen.", nextScene:'s22'}, {text:"Finish her off.", nextScene:'death_police'}] },
            's22': { text: "Stage 22: You limp back to your brother. He is unconscious but breathing.", choices: [{text:"Do CPR.", nextScene:'s23'}, {text:"Bandage your leg.", nextScene:'s23'}] },
